//! Maha 21-virtual-shard mapping for physical distributed-inference meshes.
//!
//! The coordinator always reasons over 21 virtual Maha shards. Physical
//! meshes, whether they have 1 station or 42, are projected onto that stable
//! virtual coordinate system.

pub const MAHA_ANCHOR: usize = 21;
pub const PHYLE_AXIS_COUNT: usize = 3;
pub const AXIS_SHARD_CAPACITY: usize = 7;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct MahaShardRoute {
    pub shard: usize,
    pub start: usize,
    pub end: usize,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct MahaPhysicalStationRange {
    pub station_index: usize,
    pub shard_start: usize,
    pub shard_end: usize,
}

#[inline]
pub fn map_to_maha_shard(prefix_hash: u64) -> usize {
    (prefix_hash % MAHA_ANCHOR as u64) as usize
}

#[inline]
pub fn shard_axis(shard_index: usize) -> usize {
    shard_index / AXIS_SHARD_CAPACITY
}

pub fn resolve_maha_shard_route(station_count: usize, prefix_hash: u64) -> Option<MahaShardRoute> {
    if station_count == 0 {
        return None;
    }
    let shard = map_to_maha_shard(prefix_hash);
    let start = (shard * station_count) / MAHA_ANCHOR;
    let raw_end = ((shard + 1) * station_count) / MAHA_ANCHOR;
    Some(MahaShardRoute {
        shard,
        start,
        end: raw_end.max(start + 1),
    })
}

pub fn resolve_maha_physical_station_range(
    station_count: usize,
    station_index: usize,
) -> Option<MahaPhysicalStationRange> {
    if station_count == 0 || station_index >= station_count {
        return None;
    }
    Some(MahaPhysicalStationRange {
        station_index,
        shard_start: (station_index * MAHA_ANCHOR).div_ceil(station_count),
        shard_end: ((station_index + 1) * MAHA_ANCHOR).div_ceil(station_count),
    })
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn maps_hashes_to_twenty_one_virtual_shards() {
        assert_eq!(map_to_maha_shard(0), 0);
        assert_eq!(map_to_maha_shard(20), 20);
        assert_eq!(map_to_maha_shard(21), 0);
        assert_eq!(map_to_maha_shard(u64::MAX), 15);
    }

    #[test]
    fn maps_one_station_to_all_virtual_shards() {
        assert_eq!(
            resolve_maha_shard_route(1, 5),
            Some(MahaShardRoute {
                shard: 5,
                start: 0,
                end: 1,
            }),
        );
        assert_eq!(
            resolve_maha_physical_station_range(1, 0),
            Some(MahaPhysicalStationRange {
                station_index: 0,
                shard_start: 0,
                shard_end: 21,
            }),
        );
    }

    #[test]
    fn splits_two_stations_as_eleven_ten_virtual_shards() {
        assert_eq!(
            resolve_maha_physical_station_range(2, 0),
            Some(MahaPhysicalStationRange {
                station_index: 0,
                shard_start: 0,
                shard_end: 11,
            }),
        );
        assert_eq!(
            resolve_maha_physical_station_range(2, 1),
            Some(MahaPhysicalStationRange {
                station_index: 1,
                shard_start: 11,
                shard_end: 21,
            }),
        );
        assert_eq!(resolve_maha_shard_route(2, 10).unwrap().start, 0);
        assert_eq!(resolve_maha_shard_route(2, 11).unwrap().start, 1);
    }

    #[test]
    fn splits_three_stations_as_seven_each() {
        assert_eq!(
            resolve_maha_physical_station_range(3, 0),
            Some(MahaPhysicalStationRange {
                station_index: 0,
                shard_start: 0,
                shard_end: 7,
            }),
        );
        assert_eq!(
            resolve_maha_physical_station_range(3, 1),
            Some(MahaPhysicalStationRange {
                station_index: 1,
                shard_start: 7,
                shard_end: 14,
            }),
        );
        assert_eq!(
            resolve_maha_physical_station_range(3, 2),
            Some(MahaPhysicalStationRange {
                station_index: 2,
                shard_start: 14,
                shard_end: 21,
            }),
        );
    }
}
